component.schema:
{
 "properties": {
  "spec": {
   "properties": {
    "clusters": {
     "items": {
      "properties": {
       "endpoints": {
        "items": {
         "properties": {
          "host": {
           "maxLength": 253,
           "type": "string",
           "x-kubernetes-validations": [
            {
             "message": "host must be a valid IP address or domain name",
             "rule": "isIP(self) || !format.dns1123Subdomain().validate(self).hasValue()"
            }
           ]
          },
          "port": {
           "default": 3306,
           "format": "int32",
           "type": "integer"
          }
         },
         "required": [
          "host"
         ],
         "type": "object"
        },
        "maxItems": 9,
        "minItems": 1,
        "type": "array"
       },
       "innodbClusterName": {
        "maxLength": 63,
        "type": "string",
        "x-kubernetes-validations": [
         {
          "message": "innodbClusterName must contain only alphanumeric characters",
          "rule": "self.matches('^[A-Za-z0-9]+$')"
         }
        ]
       }
      },
      "required": [
       "endpoints",
       "innodbClusterName"
      ],
      "type": "object"
     },
     "maxItems": 10,
     "minItems": 1,
     "type": "array",
     "x-kubernetes-list-map-keys": [
      "innodbClusterName"
     ],
     "x-kubernetes-list-type": "map",
     "x-kubernetes-validations": [
      {
       "message": "cluster names must be unique",
       "rule": "self.all(c, self.exists_one(d, d.innodbClusterName == c.innodbClusterName))"
      }
     ]
    },
    "createReplicaClusterOptions": {
     "properties": {
      "recoveryMethod": {
       "default": "clone",
       "enum": [
        "clone",
        "incremental",
        "auto"
       ],
       "type": "string"
      }
     },
     "type": "object"
    },
    "credentialsSecret": {
     "properties": {
      "key": {
       "type": "string"
      },
      "name": {
       "default": "",
       "type": "string"
      },
      "optional": {
       "type": "boolean"
      }
     },
     "required": [
      "key"
     ],
     "type": "object",
     "x-kubernetes-map-type": "atomic",
     "x-kubernetes-validations": [
      {
       "message": "credentialsSecret.name must be set",
       "rule": "has(self.name) \u0026\u0026 self.name != ''"
      }
     ]
    },
    "mysqlshellRunner": {
     "properties": {
      "image": {
       "minLength": 1,
       "type": "string"
      }
     },
     "required": [
      "image"
     ],
     "type": "object"
    },
    "primaryCluster": {
     "maxLength": 63,
     "type": "string",
     "x-kubernetes-validations": [
      {
       "message": "primaryCluster must contain only alphanumeric characters",
       "rule": "self.matches('^[A-Za-z0-9]+$')"
      }
     ]
    },
    "sslMode": {
     "default": "AUTO",
     "enum": [
      "AUTO",
      "DISABLED",
      "REQUIRED",
      "VERIFY_CA",
      "VERIFY_IDENTITY"
     ],
     "type": "string"
    },
    "unsafeFlags": {
     "properties": {
      "forcedClusterRemoval": {
       "default": false,
       "type": "boolean"
      },
      "forcedFailover": {
       "default": false,
       "type": "boolean"
      }
     },
     "type": "object"
    }
   },
   "required": [
    "clusters",
    "credentialsSecret",
    "mysqlshellRunner",
    "primaryCluster"
   ],
   "type": "object",
   "x-kubernetes-validations": [
    {
     "message": "spec.primaryCluster not found in spec.clusters",
     "rule": "self.clusters.exists(c, c.innodbClusterName == self.primaryCluster)"
    },
    {
     "message": "endpoint host must be unique across all clusters",
     "rule": "self.clusters.all(c, c.endpoints.all(e, self.clusters.map(c2, c2.endpoints.filter(e2, e2.host == e.host).size()).sum() == 1))"
    }
   ]
  }
 },
 "title": "Percona Server My SQL Cluster Set",
 "type": "object"
}
